(2, 'J003', 'C-001', 'Network Engineer', 'The IT Staff is responsible for providing technical support, maintaining computer systems, and ensuring the smooth operation of the organizationâs IT infrastructure. This role involves troubleshooting hardware and software issues, assisting users with technical concerns, and supporting network and system operations.', 1, '<p data-start=\"599\" data-end=\"624\"><strong data-start=\"599\" data-end=\"624\">Key Responsibilities:</strong></p>\n<ul data-start=\"625\" data-end=\"1035\">\n<li data-start=\"625\" data-end=\"710\">\n<p data-start=\"627\" data-end=\"710\">Provide technical support for desktops, laptops, printers, and other IT equipment</p>\n</li>\n<li data-start=\"711\" data-end=\"769\">\n<p data-start=\"713\" data-end=\"769\">Install, configure, and maintain hardware and software</p>\n</li>\n<li data-start=\"770\" data-end=\"826\">\n<p data-start=\"772\" data-end=\"826\">Troubleshoot system, network, and application issues</p>\n</li>\n<li data-start=\"827\" data-end=\"881\">\n<p data-start=\"829\" data-end=\"881\">Assist users with IT-related problems and requests</p>\n</li>\n<li data-start=\"882\" data-end=\"932\">\n<p data-start=\"884\" data-end=\"932\">Perform regular system maintenance and updates</p>\n</li>\n<li data-start=\"933\" data-end=\"986\">\n<p data-start=\"935\" data-end=\"986\">Maintain records of IT assets and support tickets</p>\n</li>\n<li data-start=\"987\" data-end=\"1035\">\n<p data-start=\"989\" data-end=\"1035\">Ensure data security and proper system usage</p>\n</li>\n</ul>\n<p data-start=\"1078\" data-end=\"1097\"><strong data-start=\"1078\" data-end=\"1097\">Qualifications:</strong></p>\n<ul data-start=\"1098\" data-end=\"1374\">\n<li data-start=\"1098\" data-end=\"1185\">\n<p data-start=\"1100\" data-end=\"1185\">Bachelor&rsquo;s degree or vocational training in Information Technology or related field</p>\n</li>\n<li data-start=\"1186\" data-end=\"1252\">\n<p data-start=\"1188\" data-end=\"1252\">Basic knowledge of computer hardware, software, and networking</p>\n</li>\n<li data-start=\"1253\" data-end=\"1315\">\n<p data-start=\"1255\" data-end=\"1315\">Familiarity with Windows OS and common office applications</p>\n</li>\n<li data-start=\"1316\" data-end=\"1374\">\n<p data-start=\"1318\" data-end=\"1374\">Ability to troubleshoot technical problems efficiently</p>\n</li>\n</ul>\n<p data-start=\"1376\" data-end=\"1402\"><strong data-start=\"1376\" data-end=\"1402\">Skills &amp; Competencies:</strong></p>\n<ul data-start=\"1403\" data-end=\"1589\">\n<li data-start=\"1403\" data-end=\"1451\">\n<p data-start=\"1405\" data-end=\"1451\">Strong problem-solving and analytical skills</p>\n</li>\n<li data-start=\"1452\" data-end=\"1499\">\n<p data-start=\"1454\" data-end=\"1499\">Good communication and interpersonal skills</p>\n</li>\n<li data-start=\"1500\" data-end=\"1547\">\n<p data-start=\"1502\" data-end=\"1547\">Ability to work independently and in a team</p>\n</li>\n<li data-start=\"1548\" data-end=\"1589\">\n<p data-start=\"1550\" data-end=\"1589\">Willingness to learn new technologies</p>\n</li>\n</ul>\n<p data-start=\"1591\" data-end=\"1616\"><strong data-start=\"1591\" data-end=\"1616\">Preferred (Optional):</strong></p>\n<ul data-start=\"1617\" data-end=\"1773\">\n<li data-start=\"1617\" data-end=\"1669\">\n<p data-start=\"1619\" data-end=\"1669\">Experience in IT support or technical assistance</p>\n</li>\n<li data-start=\"1670\" data-end=\"1713\">\n<p data-start=\"1672\" data-end=\"1713\">Knowledge of basic networking (LAN/WAN)</p>\n</li>\n<li data-start=\"1714\" data-end=\"1773\">\n<p data-start=\"1716\" data-end=\"1773\">Certifications such as CompTIA A+, Network+, or similar</p>\n</li>\n</ul>', 'Hiring', NULL),
(3, 'J001', 'C-002', 'Human Resources Manager', 'Responsible for overseeing the entire Human Resources department, including recruitment, employee relations, policy implementation, and workforce planning. Ensures that HR practices comply with company policies and labor laws while supporting organizational goals.', 4, '<ul>\n<li data-start=\"556\" data-end=\"649\">\n<p data-start=\"558\" data-end=\"649\">Bachelor&rsquo;s Degree in Human Resource Management, Business Administration, or related field</p>\n</li>\n<li data-start=\"650\" data-end=\"702\">\n<p data-start=\"652\" data-end=\"702\">At least <strong data-start=\"661\" data-end=\"700\">5 years experience in HR management</strong></p>\n</li>\n<li data-start=\"703\" data-end=\"751\">\n<p data-start=\"705\" data-end=\"751\">Strong leadership and decision-making skills</p>\n</li>\n<li data-start=\"752\" data-end=\"799\">\n<p data-start=\"754\" data-end=\"799\">Knowledge of <strong data-start=\"767\" data-end=\"797\">labor laws and HR policies</strong></p>\n</li>\n<li data-start=\"800\" data-end=\"852\">\n<p data-start=\"802\" data-end=\"852\">Excellent communication and interpersonal skills</p>\n</li>\n</ul>', 'Urgent', NULL);

